/* document.c -- context, document open/close, IFF/DJVM/DIRM/INFO parsing.
 * Ported from DjvuNet Parser/DjvuParser.cs + DataChunks/{DirmChunk,InfoChunk}.cs */
#include <stdlib.h>
#include <stdio.h>
#include <string.h>

/* ---- allocator + diagnostics ---- */

static void *default_alloc(void *user, size_t size) { (void)user; return malloc(size); }
static void  default_free(void *user, void *ptr) { (void)user; free(ptr); }

void *djvu_alloc(djvu_ctx *ctx, size_t size) { return ctx->alloc(ctx->user, size); }
void  djvu_free(djvu_ctx *ctx, void *ptr) { if (ptr) ctx->free(ctx->user, ptr); }

void djvu_errorf(djvu_ctx *ctx, djvu_severity sev, const char *fmt, ...)
{
    char buf[512];
    va_list ap;
    if (!ctx->error) return;
    va_start(ap, fmt);
    vsnprintf(buf, sizeof(buf), fmt, ap);
    va_end(ap);
    ctx->error(ctx->user, sev, buf);
}

djvu_ctx *djvu_ctx_new(djvu_alloc_cb alloc, djvu_free_cb free_cb,
                       djvu_error_cb error, void *user)
{
    djvu_ctx *ctx;
    djvu_alloc_cb a = alloc ? alloc : default_alloc;
    ctx = (djvu_ctx *)a(user, sizeof(djvu_ctx));
    if (!ctx) return NULL;
    ctx->alloc = a;
    ctx->free = free_cb ? free_cb : default_free;
    ctx->error = error;
    ctx->user = user;
    return ctx;
}

void djvu_ctx_free(djvu_ctx *ctx)
{
    if (ctx) ctx->free(ctx->user, ctx);
}

/* ---- INFO chunk ---- */

/* Parse an INFO chunk body at [p, p+len) into info. Returns 0 on success. */
static int parse_info(const uint8_t *p, size_t len, djvu_page_info *info)
{
    int flag;
    if (len < 5) return -1;
    info->width = (int)djvu_rd_u16be(p);
    info->height = (int)djvu_rd_u16be(p + 2);
    info->version = p[4];                       /* minor version */
    info->dpi = 300;
    info->rotation = 0;
    if (len >= 8) info->dpi = (int)djvu_rd_u16le(p + 6);  /* DPI is little-endian */
    if (len >= 10) {
        flag = p[9] & 0x7;
        switch (flag) {
            case 6: info->rotation = 90; break;   /* counter-clockwise */
            case 2: info->rotation = 180; break;  /* upside down */
            case 5: info->rotation = 270; break;  /* clockwise */
            default: info->rotation = 0; break;
        }
    }
    if (info->dpi <= 0) info->dpi = 300;
    return 0;
}

/* Find the INFO chunk inside a FORM:DJVU at form_off and fill info.
   Returns 0 on success. */
static int page_load_info(djvu_doc *doc, djvu_page_int *pg)
{
    const uint8_t *data = doc->data;
    size_t len = doc->len;
    uint32_t off = pg->form_off;
    uint32_t form_end;
    uint32_t pos;

    if (pg->has_info) return 0;
    if ((size_t)off + 12 > len) return -1;
    if (!djvu_tag_eq(data + off, "FORM")) return -1;
    form_end = off + 8 + pg->form_size;
    if (form_end > len) form_end = (uint32_t)len;

    /* sub-chunks begin after FORM(4) + size(4) + type(4) */
    pos = off + 12;
    while (pos + 8 <= form_end) {
        const uint8_t *id = data + pos;
        uint32_t csize = djvu_rd_u32be(data + pos + 4);
        uint32_t cdata = pos + 8;
        if (cdata + csize > form_end) csize = form_end - cdata;
        if (djvu_tag_eq(id, "INFO")) {
            if (parse_info(data + cdata, csize, &pg->info) == 0) {
                pg->has_info = 1;
                return 0;
            }
            return -1;
        }
        pos = cdata + csize;
        if (csize & 1) pos++;   /* chunks padded to even length */
    }
    return -1;
}

/* ---- container ---- */

static char *dup_cstr(djvu_ctx *ctx, const char *s, size_t maxlen, size_t *consumed)
{
    size_t n = 0;
    char *r;
    while (n < maxlen && s[n]) n++;
    r = (char *)djvu_alloc(ctx, n + 1);
    if (r) { memcpy(r, s, n); r[n] = 0; }
    *consumed = (n < maxlen) ? n + 1 : n;   /* skip the NUL if present */
    return r;
}

/* Parse a DJVM directory (DIRM): component offsets + BZZ-compressed
   sizes/flags/ids. Builds doc->comps and doc->pages. */
static int load_djvm(djvu_doc *doc, uint32_t dirm_data, uint32_t dirm_size)
{
    djvu_ctx *ctx = doc->ctx;
    const uint8_t *data = doc->data;
    size_t len = doc->len;
    uint32_t pos = dirm_data;
    uint32_t dirm_end = dirm_data + dirm_size;
    int count, i, npages = 0;
    int version, bundled;
    uint8_t flagbyte;
    uint8_t *dir = NULL;       /* decompressed directory */
    size_t dirlen = 0, dp = 0;
    int have_dir = 0;

    if (pos + 3 > dirm_end || dirm_end > len) return -1;
    flagbyte = data[pos++];
    bundled = (flagbyte >> 7) & 1;
    version = flagbyte & 0x7f;
    count = (int)djvu_rd_u16be(data + pos);
    pos += 2;
    if (count <= 0) return -1;

    doc->comps = (djvu_component *)djvu_alloc(ctx, sizeof(djvu_component) * count);
    doc->pages = (djvu_page_int *)djvu_alloc(ctx, sizeof(djvu_page_int) * count);
    if (!doc->comps || !doc->pages) return -1;
    memset(doc->comps, 0, sizeof(djvu_component) * count);
    memset(doc->pages, 0, sizeof(djvu_page_int) * count);
    doc->ncomp = count;

    /* component offsets (bundled documents only) */
    if (bundled) {
        if ((size_t)pos + (size_t)count * 4 > len) return -1;
        for (i = 0; i < count; i++)
            doc->comps[i].offset = djvu_rd_u32be(data + pos + (uint32_t)i * 4);
        pos += (uint32_t)count * 4;
    }

    /* BZZ-compressed section: sizes, flags, ids */
    if (pos < dirm_end) {
        dir = djvu_bzz_decode_all(ctx, data + pos, dirm_end - pos, &dirlen);
    }
    if (dir) {
        size_t flags_off, sp;
        /* sizes: u24 BE * count */
        for (i = 0; i < count && dp + 3 <= dirlen; i++, dp += 3)
            doc->comps[i].size = djvu_rd_u24be(dir + dp);
        /* flags: u8 * count */
        flags_off = dp;
        for (i = 0; i < count && dp < dirlen; i++, dp++) {
            uint8_t fl = dir[dp];
            doc->comps[i].type = (version == 0) ? ((fl & 0x01) ? 1 : 0)
                                                : (fl & 0x3f);
        }
        /* strings: id [name] [title] per component */
        sp = dp;
        for (i = 0; i < count && sp < dirlen; i++) {
            uint8_t fl = (flags_off + (size_t)i < dirlen) ? dir[flags_off + i] : 0;
            int has_name, has_title;
            size_t used;
            if (version == 0) {
                has_name = (fl & 0x02) != 0; has_title = (fl & 0x04) != 0;
            } else {
                has_name = (fl & 0x80) != 0; has_title = (fl & 0x40) != 0;
            }
            doc->comps[i].id = dup_cstr(ctx, (char *)dir + sp, dirlen - sp, &used);
            sp += used;
            if (has_name && sp < dirlen) {
                char *nm = dup_cstr(ctx, (char *)dir + sp, dirlen - sp, &used);
                djvu_free(ctx, nm); sp += used;   /* name (file name) unused */
            }
            if (has_title && sp < dirlen) {
                doc->comps[i].title = dup_cstr(ctx, (char *)dir + sp, dirlen - sp, &used);
                sp += used;
            }
        }
        djvu_free(ctx, dir);
        dir = NULL;
        have_dir = 1;
    }

    /* build page list: components of type "page" (or, fallback, FORM:DJVU). */
    for (i = 0; i < count; i++) {
        uint32_t o = doc->comps[i].offset;
        int is_page = (doc->comps[i].type == 1);
        if (!bundled) continue;
        if ((size_t)o + 12 > len || !djvu_tag_eq(data + o, "FORM")) continue;
        if (!have_dir) is_page = djvu_tag_eq(data + o + 8, "DJVU");
        if (!is_page) continue;
        doc->pages[npages].form_off = o;
        doc->pages[npages].form_size = djvu_rd_u32be(data + o + 4);
        doc->pages[npages].id = doc->comps[i].id;
        doc->pages[npages].title = doc->comps[i].title;
        npages++;
    }
    doc->npages = npages;
    return 0;
}

/* debug: list components (used by the test harness) */
void djvu_debug_dump_comps(djvu_doc *doc)
{
    int i;
    const char *tn[4] = {"incl", "page", "thumb", "anno"};
    if (!doc) return;
    printf("components: %d\n", doc->ncomp);
    for (i = 0; i < doc->ncomp; i++) {
        djvu_component *c = &doc->comps[i];
        printf("  [%d] off=%u size=%u type=%s id=%s\n", i, c->offset, c->size,
               (c->type >= 0 && c->type < 4) ? tn[c->type] : "?",
               c->id ? c->id : "(null)");
    }
}

uint32_t djvu_doc_component_offset(djvu_doc *doc, const char *id)
{
    int i;
    if (!doc || !id) return 0;
    for (i = 0; i < doc->ncomp; i++)
        if (doc->comps[i].id && strcmp(doc->comps[i].id, id) == 0)
            return doc->comps[i].offset;
    return 0;
}

const uint8_t *djvu_form_find_chunk(djvu_doc *doc, uint32_t form_off,
                                    const char *id, uint32_t *out_size,
                                    uint32_t *start)
{
    const uint8_t *data = doc->data;
    size_t len = doc->len;
    uint32_t form_size, form_end, pos;

    if ((size_t)form_off + 12 > len || !djvu_tag_eq(data + form_off, "FORM"))
        return NULL;
    form_size = djvu_rd_u32be(data + form_off + 4);
    form_end = form_off + 8 + form_size;
    if (form_end > len) form_end = (uint32_t)len;

    pos = start && *start ? *start : form_off + 12;
    while (pos + 8 <= form_end) {
        const uint8_t *cid = data + pos;
        uint32_t csize = djvu_rd_u32be(data + pos + 4);
        uint32_t cdata = pos + 8;
        uint32_t next;
        if (cdata + csize > form_end) csize = form_end - cdata;
        next = cdata + csize + (csize & 1);
        if (djvu_tag_eq(cid, id)) {
            if (out_size) *out_size = csize;
            if (start) *start = next;
            return data + cdata;
        }
        pos = next;
    }
    return NULL;
}

djvu_doc *djvu_doc_open(djvu_ctx *ctx, const uint8_t *data, size_t len)
{
    djvu_doc *doc;
    uint32_t pos = 0;
    uint32_t form_size, form_end;
    const uint8_t *form_type;

    if (!ctx || !data || len < 16) return NULL;

    /* optional "AT&T" magic */
    if (djvu_tag_eq(data, "AT&T"))
        pos = 4;

    if (pos + 12 > len || !djvu_tag_eq(data + pos, "FORM")) {
        djvu_errorf(ctx, DJVU_SEVERITY_ERROR, "not a DjVu file (no FORM)");
        return NULL;
    }
    form_size = djvu_rd_u32be(data + pos + 4);
    form_type = data + pos + 8;
    form_end = pos + 8 + form_size;
    if (form_end > len) form_end = (uint32_t)len;

    doc = (djvu_doc *)djvu_alloc(ctx, sizeof(djvu_doc));
    if (!doc) return NULL;
    memset(doc, 0, sizeof(*doc));
    doc->ctx = ctx;
    doc->data = data;
    doc->len = len;
    doc->root_form_off = pos;

    if (djvu_tag_eq(form_type, "DJVU")) {
        /* single-page document: the top form IS the page */
        doc->pages = (djvu_page_int *)djvu_alloc(ctx, sizeof(djvu_page_int));
        if (!doc->pages) { djvu_free(ctx, doc); return NULL; }
        memset(doc->pages, 0, sizeof(djvu_page_int));
        doc->pages[0].form_off = pos;
        doc->pages[0].form_size = form_size;
        doc->npages = 1;
    } else if (djvu_tag_eq(form_type, "DJVM")) {
        /* multi-page bundle: find DIRM directory */
        uint32_t p = pos + 12;
        int found = 0;
        while (p + 8 <= form_end) {
            const uint8_t *id = data + p;
            uint32_t csize = djvu_rd_u32be(data + p + 4);
            uint32_t cdata = p + 8;
            if (cdata + csize > form_end) csize = form_end - cdata;
            if (djvu_tag_eq(id, "DIRM")) {
                if (load_djvm(doc, cdata, csize) != 0) {
                    djvu_errorf(ctx, DJVU_SEVERITY_ERROR, "bad DIRM directory");
                    djvu_doc_close(doc);
                    return NULL;
                }
                found = 1;
                break;
            }
            p = cdata + csize;
            if (csize & 1) p++;
        }
        if (!found) {
            djvu_errorf(ctx, DJVU_SEVERITY_ERROR, "DJVM without DIRM");
            djvu_doc_close(doc);
            return NULL;
        }
    } else {
        djvu_errorf(ctx, DJVU_SEVERITY_ERROR, "unsupported FORM type");
        djvu_doc_close(doc);
        return NULL;
    }

    return doc;
}

void djvu_doc_close(djvu_doc *doc)
{
    int i;
    if (!doc) return;
    if (doc->comps) {
        for (i = 0; i < doc->ncomp; i++) {
            djvu_free(doc->ctx, doc->comps[i].id);
            djvu_free(doc->ctx, doc->comps[i].title);
        }
        djvu_free(doc->ctx, doc->comps);
    }
    djvu_free(doc->ctx, doc->pages);
    djvu_free(doc->ctx, doc);
}

int djvu_doc_page_count(djvu_doc *doc)
{
    return doc ? doc->npages : 0;
}

int djvu_doc_page_info(djvu_doc *doc, int page_no, djvu_page_info *info)
{
    djvu_page_int *pg;
    if (!doc || !info || page_no < 0 || page_no >= doc->npages) return -1;
    pg = &doc->pages[page_no];
    if (page_load_info(doc, pg) != 0) return -1;
    *info = pg->info;
    return 0;
}

const char *djvu_doc_page_id(djvu_doc *doc, int page_no)
{
    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    return doc->pages[page_no].id;
}

const char *djvu_doc_page_title(djvu_doc *doc, int page_no)
{
    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    return doc->pages[page_no].title;
}

int djvu_doc_page_by_name(djvu_doc *doc, const char *name)
{
    int i;
    if (!doc || !name) return -1;
    if (name[0] == '#') name++;
    for (i = 0; i < doc->npages; i++) {
        const char *id = doc->pages[i].id;
        if (id && strcmp(id, name) == 0) return i;
    }
    return -1;
}

djvu_page_type djvu_page_get_type(djvu_doc *doc, int page_no)
{
    uint32_t form_off, sz;
    int has_mask, has_bg, has_fg;
    if (!doc || page_no < 0 || page_no >= doc->npages) return DJVU_PAGE_UNKNOWN;
    form_off = doc->pages[page_no].form_off;
    has_mask = djvu_form_find_chunk(doc, form_off, "Sjbz", &sz, NULL) != NULL;
    has_bg   = djvu_form_find_chunk(doc, form_off, "BG44", &sz, NULL) != NULL;
    has_fg   = djvu_form_find_chunk(doc, form_off, "FG44", &sz, NULL) != NULL ||
               djvu_form_find_chunk(doc, form_off, "FGbz", &sz, NULL) != NULL;
    if (has_mask && (has_bg || has_fg)) return DJVU_PAGE_COMPOUND;
    if (has_mask) return DJVU_PAGE_BITONAL;
    if (has_bg || has_fg) return DJVU_PAGE_PHOTO;
    return DJVU_PAGE_UNKNOWN;
}

/* =====================================================================
 * src/render.c
 * ===================================================================== */

/* render.c -- page rendering. Milestone 3: JB2 bitonal composite.
 * (color IW44 = milestone 5). */
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

djvu_image *djvu_compose_page(djvu_doc *doc, int page_no, jb2_image *mask,
                             int width, int height);

/* trim trailing whitespace/control from an INCL id copied into buf */
static void trim_id(char *s)
{
    size_t n = strlen(s);
    while (n > 0 && (s[n - 1] == '\n' || s[n - 1] == '\r' ||
                     s[n - 1] == ' ' || s[n - 1] == '\t' || s[n - 1] == 0x1a))
        s[--n] = 0;
}

/* Decode the JB2 shape dictionary for a page: either embedded directly in the
   page form as a Djbz chunk, or referenced by an INCL chunk pointing at a
   shared DJVI component that contains the Djbz. */
static jb2_image *load_page_dict(djvu_doc *doc, uint32_t form_off)
{
    djvu_ctx *ctx = doc->ctx;
    uint32_t start = 0, sz;
    const uint8_t *incl;
    const uint8_t *djbz_inpage;

    /* in-page Djbz takes precedence */
    djbz_inpage = djvu_form_find_chunk(doc, form_off, "Djbz", &sz, NULL);
    if (djbz_inpage)
        return djvu_jb2_decode_dict(ctx, djbz_inpage, sz);

    while ((incl = djvu_form_find_chunk(doc, form_off, "INCL", &sz, &start)) != NULL) {
        char id[64];
        uint32_t coff, dsz;
        const uint8_t *djbz;
        size_t n = sz < sizeof(id) - 1 ? sz : sizeof(id) - 1;
        memcpy(id, incl, n);
        id[n] = 0;
        trim_id(id);
        coff = djvu_doc_component_offset(doc, id);
        if (!coff) continue;
        djbz = djvu_form_find_chunk(doc, coff, "Djbz", &dsz, NULL);
        if (djbz)
            return djvu_jb2_decode_dict(ctx, djbz, dsz);
    }
    return NULL;
}

/* Rotate a top-down image clockwise by k quarter-turns (k=1,2,3). Returns a
   new image; frees nothing. */
static djvu_image *image_rotate_cw(djvu_ctx *ctx, djvu_image *src, int k)
{
    int comp = (int)src->format;   /* 1 or 3 bytes/pixel */
    int sw = src->width, sh = src->height;
    int dw = (k == 2) ? sw : sh;
    int dh = (k == 2) ? sh : sw;
    djvu_image *d = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
    int x, y, c;
    if (!d) return NULL;
    d->width = dw; d->height = dh; d->format = src->format; d->stride = dw * comp;
    d->data = (uint8_t *)djvu_alloc(ctx, (size_t)dw * dh * comp);
    if (!d->data) { djvu_free(ctx, d); return NULL; }
    for (y = 0; y < dh; y++) {
        for (x = 0; x < dw; x++) {
            int sx, sy;
            if (k == 1) { sx = y; sy = sh - 1 - x; }          /* 90 CW */
            else if (k == 2) { sx = sw - 1 - x; sy = sh - 1 - y; } /* 180 */
            else { sx = sw - 1 - y; sy = x; }                  /* 270 CW */
            for (c = 0; c < comp; c++)
                d->data[((size_t)y * dw + x) * comp + c] =
                    src->data[((size_t)sy * sw + sx) * comp + c];
        }
    }
    return d;
}

djvu_image *djvu_page_render(djvu_doc *doc, int page_no, int subsample)
{
    djvu_ctx *ctx;
    djvu_page_int *pg;
    uint32_t form_off, sz;
    const uint8_t *sjbz;
    jb2_image *dict = NULL, *img = NULL;
    djvu_bitmap page;
    djvu_image *out = NULL;
    int i, y, x;

    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    if (subsample < 1) subsample = 1;
    ctx = doc->ctx;
    pg = &doc->pages[page_no];
    form_off = pg->form_off;

    {
        uint32_t cs;
        int has_bg = djvu_form_find_chunk(doc, form_off, "BG44", &cs, NULL) != NULL;
        int has_fg = djvu_form_find_chunk(doc, form_off, "FG44", &cs, NULL) != NULL;

        sjbz = djvu_form_find_chunk(doc, form_off, "Sjbz", &sz, NULL);
        if (sjbz) {
            dict = load_page_dict(doc, form_off);
            img = djvu_jb2_decode(ctx, sjbz, sz, dict);
            if (!img) goto done;
        }

        /* color/gray page: composite (background + optional mask/foreground).
           Works with img == NULL too (pure-photo pages = BG44 only). */
        if ((has_bg || has_fg) && subsample == 1 && !getenv("DJVU_NOCOMPOSE")) {
            djvu_page_info pi;
            if (djvu_doc_page_info(doc, page_no, &pi) == 0) {
                out = djvu_compose_page(doc, page_no, img, pi.width, pi.height);
                goto done;
            }
        }

        if (!sjbz) {
            /* blank page (only INFO, no image layers): render solid white */
            djvu_page_info pi;
            if (djvu_doc_page_info(doc, page_no, &pi) == 0 &&
                pi.width > 0 && pi.height > 0) {
                int sw = (pi.width + subsample - 1) / subsample;
                int sh = (pi.height + subsample - 1) / subsample;
                out = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
                if (out) {
                    out->width = sw; out->height = sh;
                    out->format = DJVU_FORMAT_GRAY8; out->stride = sw;
                    out->data = (uint8_t *)djvu_alloc(ctx, (size_t)sw * sh);
                    if (out->data) memset(out->data, 255, (size_t)sw * sh);
                    else { djvu_free(ctx, out); out = NULL; }
                }
            } else {
                djvu_errorf(ctx, DJVU_SEVERITY_ERROR,
                            "page %d: nothing to render", page_no);
            }
            goto done;
        }
    }

    /* compose mask into a full-res bottom-up bitmap (Grays=2 -> clamp 1) */
    memset(&page, 0, sizeof(page));
    if (djvu_bm_init(ctx, &page, img->height, img->width, 0) != 0) goto done;
    for (i = 0; i < img->nblits; i++) {
        jb2_blit *b = &img->blits[i];
        jb2_shape *s = djvu_jb2_get_shape(img, b->shapeno);
        if (s && s->bm.data)
            djvu_bm_blit(&page, &s->bm, b->left, b->bottom, 1);
    }

    /* emit gray8, top-down, ink(1)->0 white(0)->255, with box subsampling */
    {
        int sw = (img->width + subsample - 1) / subsample;
        int sh = (img->height + subsample - 1) / subsample;
        out = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
        if (!out) { djvu_bm_free(ctx, &page); goto done; }
        out->width = sw; out->height = sh;
        out->format = DJVU_FORMAT_GRAY8;
        out->stride = sw;
        out->data = (uint8_t *)djvu_alloc(ctx, (size_t)sw * sh);
        if (!out->data) { djvu_free(ctx, out); out = NULL; djvu_bm_free(ctx, &page); goto done; }

        if (subsample == 1) {
            for (y = 0; y < img->height; y++) {
                /* page row (img->height-1-y) is top row y (flip) */
                int srow = djvu_bm_rowoffset(&page, img->height - 1 - y);
                uint8_t *dst = out->data + (size_t)y * sw;
                for (x = 0; x < img->width; x++)
                    dst[x] = page.data[srow + x] ? 0 : 255;
            }
        } else {
            for (y = 0; y < sh; y++) {
                uint8_t *dst = out->data + (size_t)y * sw;
                for (x = 0; x < sw; x++) {
                    int cnt = 0, tot = 0, yy, xx;
                    for (yy = 0; yy < subsample; yy++) {
                        int py = y * subsample + yy;
                        int srow;
                        if (py >= img->height) break;
                        srow = djvu_bm_rowoffset(&page, img->height - 1 - py);
                        for (xx = 0; xx < subsample; xx++) {
                            int px = x * subsample + xx;
                            if (px >= img->width) continue;
                            tot++;
                            if (page.data[srow + px]) cnt++;
                        }
                    }
                    dst[x] = tot ? (uint8_t)(255 - (cnt * 255 / tot)) : 255;
                }
            }
        }
    }
    djvu_bm_free(ctx, &page);

done:
    djvu_jb2_free(ctx, img);
    djvu_jb2_free(ctx, dict);
    /* apply page rotation (INFO flag) to match ddjvu's upright display */
    if (out && subsample == 1) {
        djvu_page_info pi;
        if (djvu_doc_page_info(doc, page_no, &pi) == 0 && pi.rotation != 0) {
            int k = (pi.rotation == 90) ? 3 : (pi.rotation == 180) ? 2 : 1;
            djvu_image *r = image_rotate_cw(ctx, out, k);
            if (r) { djvu_image_destroy(ctx, out); out = r; }
        }
    }
    return out;
}

void djvu_image_destroy(djvu_ctx *ctx, djvu_image *img)
{
    if (img) {
        djvu_free(ctx, img->data);
        djvu_free(ctx, img);
    }
}

/* ---- debug/verification helpers ---- */

/* Decode a page's BG44 (kind=0) or FG44 (kind=1) IW44 chunks via our decoder,
   returning the native-resolution RGB image. */
djvu_image *djvu_debug_render_iw(djvu_doc *doc, int page_no, int kind)
{
    djvu_ctx *ctx;
    uint32_t form_off, start = 0, sz;
    const uint8_t *chunk;
    const char *id = kind ? "FG44" : "BG44";
    iw_pixmap *pm;
    djvu_image *out = NULL;
    int w, h;

    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx;
    form_off = doc->pages[page_no].form_off;
    pm = djvu_iw44_new(ctx);
    if (!pm) return NULL;
    {
        const char *mc = getenv("DJVU_IW_MAXCHUNKS");
        int maxc = mc ? atoi(mc) : 1000, nc = 0;
        while ((chunk = djvu_form_find_chunk(doc, form_off, id, &sz, &start)) != NULL) {
            if (nc++ >= maxc) break;
            if (djvu_iw44_decode_chunk(pm, chunk, sz) != 0) { djvu_iw44_free(pm); return NULL; }
        }
    }
    w = djvu_iw44_width(pm); h = djvu_iw44_height(pm);
    if (w <= 0 || h <= 0) { djvu_iw44_free(pm); return NULL; }
    out = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
    if (!out) { djvu_iw44_free(pm); return NULL; }
    out->width = w; out->height = h; out->format = DJVU_FORMAT_RGB24;
    out->stride = w * 3;
    out->data = (uint8_t *)djvu_alloc(ctx, (size_t)w * h * 3);
    if (!out->data || djvu_iw44_render_rgb(pm, out->data) != 0) {
        djvu_image_destroy(ctx, out); djvu_iw44_free(pm); return NULL;
    }
    djvu_iw44_free(pm);
    return out;
}

/* Render a page's BG44/FG44 Y (luma) plane as gray (Y+128) -- for isolating
   the luma transform from the color conversion. */
djvu_image *djvu_debug_render_iw_gray(djvu_doc *doc, int page_no, int kind)
{
    djvu_ctx *ctx;
    uint32_t form_off, start = 0, sz;
    const uint8_t *chunk;
    const char *id = kind ? "FG44" : "BG44";
    iw_pixmap *pm;
    djvu_image *out = NULL;
    int w, h;
    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx;
    form_off = doc->pages[page_no].form_off;
    pm = djvu_iw44_new(ctx);
    if (!pm) return NULL;
    while ((chunk = djvu_form_find_chunk(doc, form_off, id, &sz, &start)) != NULL)
        if (djvu_iw44_decode_chunk(pm, chunk, sz) != 0) { djvu_iw44_free(pm); return NULL; }
    w = djvu_iw44_width(pm); h = djvu_iw44_height(pm);
    if (w <= 0 || h <= 0) { djvu_iw44_free(pm); return NULL; }
    out = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
    if (!out) { djvu_iw44_free(pm); return NULL; }
    out->width = w; out->height = h; out->format = DJVU_FORMAT_GRAY8; out->stride = w;
    out->data = (uint8_t *)djvu_alloc(ctx, (size_t)w * h);
    if (!out->data || djvu_iw44_render_gray(pm, out->data) != 0) {
        djvu_image_destroy(ctx, out); djvu_iw44_free(pm); return NULL;
    }
    djvu_iw44_free(pm);
    return out;
}

djvu_image *djvu_debug_render_iw_plane(djvu_doc *doc, int page_no, int kind, int plane)
{
    djvu_ctx *ctx; uint32_t form_off, start = 0, sz; const uint8_t *chunk;
    const char *id = kind ? "FG44" : "BG44"; iw_pixmap *pm; djvu_image *out;
    int w, h;
    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx; form_off = doc->pages[page_no].form_off;
    pm = djvu_iw44_new(ctx); if (!pm) return NULL;
    while ((chunk = djvu_form_find_chunk(doc, form_off, id, &sz, &start)) != NULL)
        if (djvu_iw44_decode_chunk(pm, chunk, sz) != 0) { djvu_iw44_free(pm); return NULL; }
    w = djvu_iw44_width(pm); h = djvu_iw44_height(pm);
    if (w <= 0 || h <= 0) { djvu_iw44_free(pm); return NULL; }
    out = (djvu_image *)djvu_alloc(ctx, sizeof(djvu_image));
    if (!out) { djvu_iw44_free(pm); return NULL; }
    out->width = w; out->height = h; out->format = DJVU_FORMAT_GRAY8; out->stride = w;
    out->data = (uint8_t *)djvu_alloc(ctx, (size_t)w * h);
    if (!out->data || djvu_iw44_render_plane(pm, plane, out->data) != 0) {
        djvu_image_destroy(ctx, out); djvu_iw44_free(pm); return NULL;
    }
    djvu_iw44_free(pm);
    return out;
}

static void put_u32be(FILE *f, uint32_t v)
{
    fputc((v >> 24) & 0xff, f); fputc((v >> 16) & 0xff, f);
    fputc((v >> 8) & 0xff, f); fputc(v & 0xff, f);
}

/* Write a standalone AT&TFORM:PM44 file from the page's BG44/FG44 chunks
   (renamed to PM44) so DjVuLibre ddjvu can render the same IW44 data. */
int djvu_debug_dump_iw(djvu_doc *doc, int page_no, int kind, const char *path)
{
    uint32_t form_off, start = 0, sz;
    const uint8_t *chunk;
    const char *id = kind ? "FG44" : "BG44";
    FILE *f;
    uint32_t total = 4;  /* "PM44" type */
    const uint8_t *chunks[64]; uint32_t sizes[64]; int n = 0, i;

    if (!doc || page_no < 0 || page_no >= doc->npages) return -1;
    form_off = doc->pages[page_no].form_off;
    {
    const char *mc = getenv("DJVU_IW_MAXCHUNKS");
    int maxc = mc ? atoi(mc) : 1000;
    while ((chunk = djvu_form_find_chunk(doc, form_off, id, &sz, &start)) != NULL && n < 64) {
        if (n >= maxc) break;
        chunks[n] = chunk; sizes[n] = sz; n++;
        total += 8 + sz + (sz & 1);
    }
    }
    if (n == 0) return -1;
    f = fopen(path, "wb");
    if (!f) return -1;
    fwrite("AT&TFORM", 1, 8, f);
    put_u32be(f, total);
    fwrite("PM44", 1, 4, f);
    for (i = 0; i < n; i++) {
        fwrite("PM44", 1, 4, f);
        put_u32be(f, sizes[i]);
        fwrite(chunks[i], 1, sizes[i], f);
        if (sizes[i] & 1) fputc(0, f);
    }
    fclose(f);
    return 0;
}

/* =====================================================================
 * src/text.c
 * ===================================================================== */

/* text.c -- hidden text extraction. Ported from DjvuNet DataChunks/Text.
 * TXTz = BZZ-compressed, TXTa = raw. Payload: u24-BE text length, UTF-8 text,
 * version byte, then a recursive zone tree (per DjvuNet TextChunk/TextZone). */
#include <string.h>

/* Locate and (if needed) decompress the text payload for a page.
   On success returns the payload pointer in *payload and its length in *plen,
   and sets *owned to a buffer the caller must djvu_free (NULL for raw TXTa).
   Returns 0 on success, -1 if the page has no text. */
static int load_text_payload(djvu_doc *doc, int page_no, uint8_t **owned,
                             const uint8_t **payload, size_t *plen)
{
    djvu_ctx *ctx = doc->ctx;
    uint32_t form_off, sz;
    const uint8_t *chunk;

    *owned = NULL;
    form_off = doc->pages[page_no].form_off;

    chunk = djvu_form_find_chunk(doc, form_off, "TXTz", &sz, NULL);
    if (chunk) {
        size_t dlen;
        uint8_t *dec = djvu_bzz_decode_all(ctx, chunk, sz, &dlen);
        if (!dec) return -1;
        *owned = dec; *payload = dec; *plen = dlen;
        return 0;
    }
    chunk = djvu_form_find_chunk(doc, form_off, "TXTa", &sz, NULL);
    if (!chunk) return -1;
    *payload = chunk; *plen = sz;
    return 0;
}

char *djvu_page_text(djvu_doc *doc, int page_no)
{
    djvu_ctx *ctx;
    uint8_t *owned = NULL;
    const uint8_t *payload;
    size_t plen;
    uint32_t tlen;
    char *out;

    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx;
    if (load_text_payload(doc, page_no, &owned, &payload, &plen) != 0) return NULL;

    if (plen < 3) { djvu_free(ctx, owned); return NULL; }
    tlen = djvu_rd_u24be(payload);
    if ((size_t)tlen + 3 > plen) tlen = (uint32_t)(plen - 3);

    out = (char *)djvu_alloc(ctx, tlen + 1);
    if (out) {
        memcpy(out, payload + 3, tlen);
        out[tlen] = 0;
    }
    djvu_free(ctx, owned);
    return out;
}

void djvu_text_destroy(djvu_ctx *ctx, char *text)
{
    djvu_free(ctx, text);
}

/* ---- structured text (zone tree) ---- */

typedef struct {
    djvu_ctx *ctx;
    const uint8_t *p;     /* payload */
    size_t len, pos;      /* cursor */
    const char *text;     /* full UTF-8 text */
    size_t textlen;
    int failed;
} zparse;

static int zp_u8(zparse *z) {
    if (z->pos >= z->len) { z->failed = 1; return 0; }
    return z->p[z->pos++];
}
static int zp_s16(zparse *z) {   /* u16-BE biased by 0x8000 */
    int v;
    if (z->pos + 2 > z->len) { z->failed = 1; return 0; }
    v = (int)djvu_rd_u16be(z->p + z->pos) - 0x8000;
    z->pos += 2;
    return v;
}
static int zp_u24(zparse *z) {
    int v;
    if (z->pos + 3 > z->len) { z->failed = 1; return 0; }
    v = (int)djvu_rd_u24be(z->p + z->pos);
    z->pos += 3;
    return v;
}

/* Copy the covered text [off, off+len) as a fresh NUL-terminated string. */
static char *zone_text(zparse *z, int off, int len)
{
    char *s;
    int avail;
    if (off < 0) off = 0;
    if (off > (int)z->textlen) off = (int)z->textlen;
    avail = (int)z->textlen - off;
    if (len < 0) len = 0;
    if (len > avail) len = avail;
    s = (char *)djvu_alloc(z->ctx, (size_t)len + 1);
    if (!s) return NULL;
    memcpy(s, z->text + off, (size_t)len);
    s[len] = 0;
    return s;
}

static void free_zone_kids(djvu_ctx *ctx, djvu_text_zone *z);

/* Parse one zone into *out (coords kept bottom-up here), resolving offsets
   relative to its parent / previous sibling exactly as DjvuNet TextZone does.
   Returns 0 on success. */
static int parse_zone(zparse *z, djvu_text_zone *out,
                      const djvu_text_zone *parent, const djvu_text_zone *sib,
                      int parent_toff, int sib_toff, int sib_tlen,
                      int *out_toff, int *out_tlen)
{
    int type, x, y, w, h, toff, tlen, nkids, i;
    djvu_text_zone *prev = NULL;
    int prev_toff = 0, prev_tlen = 0;

    type = zp_u8(z);
    x = zp_s16(z); y = zp_s16(z); w = zp_s16(z); h = zp_s16(z);
    toff = zp_s16(z);
    tlen = zp_u24(z);
    if (z->failed) return -1;

    /* ResolveOffsets (DjvuNet TextZone.ResolveOffsets), bottom-up coords */
    if (parent == NULL && sib == NULL) {
        /* absolute (page zone) */
    } else if (sib == NULL) {
        x += parent->x;
        y = (parent->y + parent->h) - (y + h);
        toff += parent_toff;
    } else {
        if (sib->type == DJVU_ZONE_PAGE || sib->type == DJVU_ZONE_PARAGRAPH ||
            sib->type == DJVU_ZONE_LINE) {
            x += sib->x;
            y = sib->y - (y + h);
        } else if (sib->type == DJVU_ZONE_COLUMN || sib->type == DJVU_ZONE_WORD ||
                   sib->type == DJVU_ZONE_CHAR) {
            x += sib->x + sib->w;
            y += sib->y;
        }
        /* (Region siblings leave x,y unadjusted, matching DjvuNet) */
        toff += sib_toff + sib_tlen;
    }

    out->type = (djvu_zone_type)type;
    out->x = x; out->y = y; out->w = w; out->h = h;
    out->text = zone_text(z, toff, tlen);
    out->children = NULL;
    out->nchildren = 0;
    if (out_toff) *out_toff = toff;
    if (out_tlen) *out_tlen = tlen;

    nkids = zp_u24(z);
    if (z->failed || nkids < 0) return -1;
    if (nkids > 0) {
        out->children = (djvu_text_zone *)djvu_alloc(z->ctx,
                            sizeof(djvu_text_zone) * (size_t)nkids);
        if (!out->children) return -1;
        memset(out->children, 0, sizeof(djvu_text_zone) * (size_t)nkids);
        for (i = 0; i < nkids; i++) {
            int kt = 0, kl = 0;
            if (parse_zone(z, &out->children[i], out, prev,
                           toff, prev_toff, prev_tlen, &kt, &kl) != 0) {
                out->nchildren = i;   /* free what we built */
                return -1;
            }
            prev = &out->children[i];
            prev_toff = kt; prev_tlen = kl;
        }
        out->nchildren = nkids;
    }
    return 0;
}

/* Recursively flip y from bottom-up (DjVu) to top-down (image) coords. */
static void flip_zone_y(djvu_text_zone *z, int page_h)
{
    int i;
    z->y = page_h - (z->y + z->h);
    for (i = 0; i < z->nchildren; i++) flip_zone_y(&z->children[i], page_h);
}

static void free_zone_kids(djvu_ctx *ctx, djvu_text_zone *z)
{
    int i;
    for (i = 0; i < z->nchildren; i++) free_zone_kids(ctx, &z->children[i]);
    djvu_free(ctx, z->children);
    djvu_free(ctx, z->text);
}

djvu_page_text_zones *djvu_page_text_get_zones(djvu_doc *doc, int page_no)
{
    djvu_ctx *ctx;
    uint8_t *owned = NULL;
    const uint8_t *payload;
    size_t plen;
    uint32_t tlen;
    zparse z;
    djvu_page_text_zones *res;
    djvu_page_info info;
    int page_h;

    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx;
    if (load_text_payload(doc, page_no, &owned, &payload, &plen) != 0) return NULL;
    if (plen < 4) { djvu_free(ctx, owned); return NULL; }

    tlen = djvu_rd_u24be(payload);
    if ((size_t)tlen + 3 > plen) tlen = (uint32_t)(plen - 3);

    res = (djvu_page_text_zones *)djvu_alloc(ctx, sizeof(*res));
    if (!res) { djvu_free(ctx, owned); return NULL; }
    res->text = (char *)djvu_alloc(ctx, tlen + 1);
    res->root = NULL;
    if (!res->text) { djvu_free(ctx, owned); djvu_free(ctx, res); return NULL; }
    memcpy(res->text, payload + 3, tlen);
    res->text[tlen] = 0;

    /* after text: version byte, then the root (page) zone */
    memset(&z, 0, sizeof(z));
    z.ctx = ctx;
    z.p = payload;
    z.len = plen;
    z.pos = (size_t)3 + tlen + 1;   /* skip length, text, version byte */
    z.text = res->text;
    z.textlen = tlen;

    if (z.pos < plen) {
        djvu_text_zone *root = (djvu_text_zone *)djvu_alloc(ctx, sizeof(*root));
        if (root) {
            memset(root, 0, sizeof(*root));
            if (parse_zone(&z, root, NULL, NULL, 0, 0, 0, NULL, NULL) == 0) {
                page_h = (djvu_doc_page_info(doc, page_no, &info) == 0)
                             ? info.height : (root->y + root->h);
                flip_zone_y(root, page_h);
                res->root = root;
            } else {
                free_zone_kids(ctx, root);
                djvu_free(ctx, root);
            }
        }
    }

    djvu_free(ctx, owned);
    return res;
}

void djvu_text_zones_destroy(djvu_ctx *ctx, djvu_page_text_zones *z)
{
    if (!z) return;
    if (z->root) {
        free_zone_kids(ctx, z->root);
        djvu_free(ctx, z->root);
    }
    djvu_free(ctx, z->text);
    djvu_free(ctx, z);
}

/* =====================================================================
 * src/outline.c
 * ===================================================================== */

/* outline.c -- document outline / bookmarks (NAVM chunk).
 * Ported from DjvuNet DataChunks/NavmChunk.cs + Navigation/Bookmark.cs.
 * NAVM is BZZ-compressed: u16-BE total bookmark count, then a forest of
 * bookmarks; each = u8 child-count, u24-BE name length + UTF-8 name,
 * u24-BE url length + UTF-8 url, then child-count children. */
#include <string.h>
#include <stdlib.h>

typedef struct {
    djvu_ctx *ctx;
    const uint8_t *p;
    size_t len, pos;
    int failed;
    int count;       /* total bookmark nodes parsed so far */
} nparse;

static int np_u8(nparse *n) {
    if (n->pos >= n->len) { n->failed = 1; return 0; }
    return n->p[n->pos++];
}
static int np_u16(nparse *n) {
    int v;
    if (n->pos + 2 > n->len) { n->failed = 1; return 0; }
    v = (int)djvu_rd_u16be(n->p + n->pos); n->pos += 2; return v;
}
static int np_u24(nparse *n) {
    int v;
    if (n->pos + 3 > n->len) { n->failed = 1; return 0; }
    v = (int)djvu_rd_u24be(n->p + n->pos); n->pos += 3; return v;
}
static char *np_str(nparse *n, int slen) {
    char *s;
    if (slen < 0 || n->pos + (size_t)slen > n->len) { n->failed = 1; return NULL; }
    s = (char *)djvu_alloc(n->ctx, (size_t)slen + 1);
    if (!s) { n->failed = 1; return NULL; }
    memcpy(s, n->p + n->pos, (size_t)slen);
    s[slen] = 0;
    n->pos += (size_t)slen;
    return s;
}

/* Resolve a bookmark url to a 0-based page number, or -1. */
static int resolve_url(djvu_doc *doc, const char *url)
{
    const char *s = url;
    int allnum = 1, n;
    if (!s || !*s) return -1;
    if (*s == '#') s++;
    if (!*s) return -1;
    { const char *t = s; for (; *t; t++) if (*t < '0' || *t > '9') { allnum = 0; break; } }
    if (allnum) {
        n = atoi(s) - 1;   /* DjVu page links are 1-based */
        if (n >= 0 && n < doc->npages) return n;
        return -1;
    }
    return djvu_doc_page_by_name(doc, s);
}

static void free_items(djvu_ctx *ctx, djvu_outline_item *items, int n);

/* Parse one bookmark (and its subtree) into *out. Returns 0 on success. */
static int parse_item(nparse *np, djvu_doc *doc, djvu_outline_item *out)
{
    int nkids, namelen, urllen, i;

    np->count++;
    nkids = np_u8(np);
    namelen = np_u24(np);
    out->title = np_str(np, namelen);
    urllen = np_u24(np);
    out->url = np_str(np, urllen);
    out->page_no = out->url ? resolve_url(doc, out->url) : -1;
    out->children = NULL;
    out->nchildren = 0;
    if (np->failed) return -1;

    if (nkids > 0) {
        out->children = (djvu_outline_item *)djvu_alloc(np->ctx,
                            sizeof(djvu_outline_item) * (size_t)nkids);
        if (!out->children) return -1;
        memset(out->children, 0, sizeof(djvu_outline_item) * (size_t)nkids);
        for (i = 0; i < nkids; i++) {
            if (parse_item(np, doc, &out->children[i]) != 0) {
                out->nchildren = i;
                return -1;
            }
        }
        out->nchildren = nkids;
    }
    return 0;
}

static void free_items(djvu_ctx *ctx, djvu_outline_item *items, int n)
{
    int i;
    if (!items) return;
    for (i = 0; i < n; i++) {
        free_items(ctx, items[i].children, items[i].nchildren);
        djvu_free(ctx, items[i].title);
        djvu_free(ctx, items[i].url);
    }
    djvu_free(ctx, items);
}

djvu_outline_item *djvu_doc_outline(djvu_doc *doc)
{
    djvu_ctx *ctx;
    const uint8_t *navm;
    uint32_t sz;
    uint8_t *dec;
    size_t dlen;
    nparse np;
    int total, cap, n;
    djvu_outline_item *items = NULL, *root;

    if (!doc) return NULL;
    ctx = doc->ctx;
    navm = djvu_form_find_chunk(doc, doc->root_form_off, "NAVM", &sz, NULL);
    if (!navm) return NULL;

    dec = djvu_bzz_decode_all(ctx, navm, sz, &dlen);
    if (!dec) return NULL;

    memset(&np, 0, sizeof(np));
    np.ctx = ctx; np.p = dec; np.len = dlen;
    total = np_u16(&np);
    if (np.failed || total <= 0) { djvu_free(ctx, dec); return NULL; }

    /* read top-level bookmarks until we've consumed `total` bookmarks */
    cap = 0; n = 0;
    while (!np.failed && np.pos < dlen && np.count < total) {
        djvu_outline_item tmp;
        memset(&tmp, 0, sizeof(tmp));
        if (parse_item(&np, doc, &tmp) != 0) {
            free_items(ctx, tmp.children, tmp.nchildren);
            djvu_free(ctx, tmp.title); djvu_free(ctx, tmp.url);
            break;
        }
        /* grow array */
        if (n == cap) {
            int ncap = cap ? cap * 2 : 8;
            djvu_outline_item *na = (djvu_outline_item *)djvu_alloc(ctx,
                                        sizeof(djvu_outline_item) * (size_t)ncap);
            if (!na) { free_items(ctx, tmp.children, tmp.nchildren);
                       djvu_free(ctx, tmp.title); djvu_free(ctx, tmp.url); break; }
            if (items) { memcpy(na, items, sizeof(djvu_outline_item) * (size_t)n);
                         djvu_free(ctx, items); }
            items = na; cap = ncap;
        }
        items[n++] = tmp;
    }

    djvu_free(ctx, dec);

    if (n == 0) { djvu_free(ctx, items); return NULL; }

    /* synthetic root holding the top-level bookmarks */
    root = (djvu_outline_item *)djvu_alloc(ctx, sizeof(*root));
    if (!root) { free_items(ctx, items, n); return NULL; }
    memset(root, 0, sizeof(*root));
    root->page_no = -1;
    root->children = items;
    root->nchildren = n;
    return root;
}

void djvu_outline_destroy(djvu_ctx *ctx, djvu_outline_item *root)
{
    if (!root) return;
    free_items(ctx, root->children, root->nchildren);
    djvu_free(ctx, root);
}

/* =====================================================================
 * src/annot.c
 * ===================================================================== */

/* annot.c -- page hyperlinks from annotation chunks (ANTa raw / ANTz BZZ).
 * Annotations are a DjVuLibre S-expression list; hyperlinks are (maparea ...)
 * forms: (maparea url comment (shape x y w h ...) ...). Mirrors what
 * ddjvu_anno_get_hyperlinks extracts (rect/oval/text shapes). */
#include <string.h>
#include <stdlib.h>

/* ---- tiny S-expression parser ---- */

typedef struct snode {
    int kind;            /* 0 = list, 1 = atom (symbol/number/string) */
    char *text;          /* atom value (decoded), NUL-terminated */
    struct snode **kids; /* list children */
    int nkids, cap;
} snode;

typedef struct {
    djvu_ctx *ctx;
    const char *s;
    size_t len, pos;
} sparse;

static void snode_free(djvu_ctx *ctx, snode *n)
{
    int i;
    if (!n) return;
    for (i = 0; i < n->nkids; i++) snode_free(ctx, n->kids[i]);
    djvu_free(ctx, n->kids);
    djvu_free(ctx, n->text);
    djvu_free(ctx, n);
}

static void snode_add(sparse *sp, snode *list, snode *kid)
{
    if (list->nkids == list->cap) {
        int nc = list->cap ? list->cap * 2 : 8;
        snode **na = (snode **)djvu_alloc(sp->ctx, sizeof(snode *) * (size_t)nc);
        if (!na) { snode_free(sp->ctx, kid); return; }
        if (list->kids) {
            memcpy(na, list->kids, sizeof(snode *) * (size_t)list->nkids);
            djvu_free(sp->ctx, list->kids);
        }
        list->kids = na; list->cap = nc;
    }
    list->kids[list->nkids++] = kid;
}

static void skip_ws(sparse *sp)
{
    while (sp->pos < sp->len) {
        char c = sp->s[sp->pos];
        if (c == ' ' || c == '\t' || c == '\r' || c == '\n' || c == '\f')
            sp->pos++;
        else
            break;
    }
}

/* Parse a quoted string starting at the opening '"'. */
static snode *parse_string(sparse *sp)
{
    djvu_ctx *ctx = sp->ctx;
    size_t cap = 16, n = 0;
    char *buf = (char *)djvu_alloc(ctx, cap);
    snode *node;
    if (!buf) return NULL;
    sp->pos++;   /* opening quote */
    while (sp->pos < sp->len) {
        char c = sp->s[sp->pos++];
        if (c == '"') break;
        if (c == '\\' && sp->pos < sp->len) {
            char e = sp->s[sp->pos++];
            switch (e) {
                case 'n': c = '\n'; break;
                case 't': c = '\t'; break;
                case 'r': c = '\r'; break;
                case 'f': c = '\f'; break;
                case 'b': c = '\b'; break;
                default:  c = e;    break;   /* \" \\ and any other */
            }
        }
        if (n + 1 >= cap) {
            char *nb = (char *)djvu_alloc(ctx, cap * 2);
            if (!nb) { djvu_free(ctx, buf); return NULL; }
            memcpy(nb, buf, n); djvu_free(ctx, buf); buf = nb; cap *= 2;
        }
        buf[n++] = c;
    }
    buf[n] = 0;
    node = (snode *)djvu_alloc(ctx, sizeof(snode));
    if (!node) { djvu_free(ctx, buf); return NULL; }
    memset(node, 0, sizeof(*node));
    node->kind = 1; node->text = buf;
    return node;
}

/* Parse a bare symbol/number token. */
static snode *parse_atom(sparse *sp)
{
    djvu_ctx *ctx = sp->ctx;
    size_t start = sp->pos;
    snode *node;
    char *buf;
    size_t n;
    while (sp->pos < sp->len) {
        char c = sp->s[sp->pos];
        if (c == ' ' || c == '\t' || c == '\r' || c == '\n' || c == '\f' ||
            c == '(' || c == ')' || c == '"')
            break;
        sp->pos++;
    }
    n = sp->pos - start;
    buf = (char *)djvu_alloc(ctx, n + 1);
    if (!buf) return NULL;
    memcpy(buf, sp->s + start, n); buf[n] = 0;
    node = (snode *)djvu_alloc(ctx, sizeof(snode));
    if (!node) { djvu_free(ctx, buf); return NULL; }
    memset(node, 0, sizeof(*node));
    node->kind = 1; node->text = buf;
    return node;
}

static snode *parse_node(sparse *sp);

static snode *parse_list(sparse *sp)
{
    djvu_ctx *ctx = sp->ctx;
    snode *list = (snode *)djvu_alloc(ctx, sizeof(snode));
    if (!list) return NULL;
    memset(list, 0, sizeof(*list));
    list->kind = 0;
    sp->pos++;   /* opening paren */
    for (;;) {
        skip_ws(sp);
        if (sp->pos >= sp->len) break;
        if (sp->s[sp->pos] == ')') { sp->pos++; break; }
        {
            snode *kid = parse_node(sp);
            if (!kid) break;
            snode_add(sp, list, kid);
        }
    }
    return list;
}

static snode *parse_node(sparse *sp)
{
    skip_ws(sp);
    if (sp->pos >= sp->len) return NULL;
    if (sp->s[sp->pos] == '(') return parse_list(sp);
    if (sp->s[sp->pos] == '"') return parse_string(sp);
    if (sp->s[sp->pos] == ')') return NULL;
    return parse_atom(sp);
}

/* ---- link extraction ---- */

static const char *atom_text(const snode *n)
{
    return (n && n->kind == 1) ? n->text : NULL;
}
static int is_list_head(const snode *n, const char *head)
{
    return n && n->kind == 0 && n->nkids > 0 &&
           atom_text(n->kids[0]) && strcmp(atom_text(n->kids[0]), head) == 0;
}

typedef struct {
    djvu_ctx *ctx;
    djvu_doc *doc;
    int page_h;
    djvu_link *links;
    int n, cap;
} lcollect;

static char *dup_str(djvu_ctx *ctx, const char *s)
{
    size_t n;
    char *r;
    if (!s) return NULL;
    n = strlen(s);
    r = (char *)djvu_alloc(ctx, n + 1);
    if (r) memcpy(r, s, n + 1);
    return r;
}

static void collect_maparea(lcollect *lc, const snode *area)
{
    const snode *url_node = NULL, *comment_node = NULL, *shape = NULL;
    const char *url = NULL, *comment = NULL, *head;
    djvu_link_shape stype;
    int i, x, y, w, h;

    /* maparea kids: head, url, comment, shape, [effects...] (order varies) */
    for (i = 1; i < area->nkids; i++) {
        const snode *k = area->kids[i];
        if (!shape && k->kind == 0) {
            head = atom_text(k->kids ? k->kids[0] : NULL);
            if (head && (!strcmp(head, "rect") || !strcmp(head, "oval") ||
                         !strcmp(head, "text") || !strcmp(head, "poly") ||
                         !strcmp(head, "line"))) {
                shape = k; continue;
            }
        }
        if (!url_node) { url_node = k; continue; }
        if (!comment_node && k->kind == 1) { comment_node = k; continue; }
    }

    if (url_node) {
        if (url_node->kind == 1) url = url_node->text;
        else if (is_list_head(url_node, "url") && url_node->nkids >= 2)
            url = atom_text(url_node->kids[1]);
    }
    if (comment_node) comment = atom_text(comment_node);
    if (!url || !*url || !shape) return;

    head = atom_text(shape->kids[0]);
    if (!strcmp(head, "oval")) stype = DJVU_LINK_OVAL;
    else if (!strcmp(head, "text")) stype = DJVU_LINK_TEXT;
    else if (!strcmp(head, "rect")) stype = DJVU_LINK_RECT;
    else return;   /* poly/line: no axis-aligned box (matches SumatraPDF) */

    if (shape->nkids < 5) return;
    x = atoi(atom_text(shape->kids[1]) ? atom_text(shape->kids[1]) : "0");
    y = atoi(atom_text(shape->kids[2]) ? atom_text(shape->kids[2]) : "0");
    w = atoi(atom_text(shape->kids[3]) ? atom_text(shape->kids[3]) : "0");
    h = atoi(atom_text(shape->kids[4]) ? atom_text(shape->kids[4]) : "0");

    if (lc->n == lc->cap) {
        int nc = lc->cap ? lc->cap * 2 : 8;
        djvu_link *na = (djvu_link *)djvu_alloc(lc->ctx, sizeof(djvu_link) * (size_t)nc);
        if (!na) return;
        if (lc->links) {
            memcpy(na, lc->links, sizeof(djvu_link) * (size_t)lc->n);
            djvu_free(lc->ctx, lc->links);
        }
        lc->links = na; lc->cap = nc;
    }
    {
        djvu_link *L = &lc->links[lc->n++];
        L->url = dup_str(lc->ctx, url);
        L->comment = (comment && *comment) ? dup_str(lc->ctx, comment) : NULL;
        L->shape = stype;
        L->x = x;
        L->y = lc->page_h - (y + h);   /* flip to top-down */
        L->w = w;
        L->h = h;
    }
}

static void walk(lcollect *lc, const snode *n)
{
    int i;
    if (!n || n->kind != 0) return;
    if (is_list_head(n, "maparea")) collect_maparea(lc, n);
    for (i = 0; i < n->nkids; i++) walk(lc, n->kids[i]);
}

/* Find the annotation buffer for a page: page form first, else a shared DJVI
   component referenced by INCL. Returns a freshly allocated NUL-terminated
   buffer (set *owned), or NULL. */
static char *load_anno(djvu_doc *doc, uint32_t form_off, size_t *out_len)
{
    djvu_ctx *ctx = doc->ctx;
    uint32_t sz, start;
    const uint8_t *chunk;

    chunk = djvu_form_find_chunk(doc, form_off, "ANTz", &sz, NULL);
    if (chunk) {
        uint8_t *dec = djvu_bzz_decode_all(ctx, chunk, sz, out_len);
        return (char *)dec;
    }
    chunk = djvu_form_find_chunk(doc, form_off, "ANTa", &sz, NULL);
    if (chunk) {
        char *buf = (char *)djvu_alloc(ctx, sz + 1);
        if (!buf) return NULL;
        memcpy(buf, chunk, sz); buf[sz] = 0;
        *out_len = sz;
        return buf;
    }
    /* shared annotation via INCL -> DJVI */
    start = 0;
    while ((chunk = djvu_form_find_chunk(doc, form_off, "INCL", &sz, &start)) != NULL) {
        char id[64];
        uint32_t coff;
        size_t n = sz < sizeof(id) - 1 ? sz : sizeof(id) - 1;
        size_t k = n;
        memcpy(id, chunk, n); id[n] = 0;
        while (k > 0 && (id[k-1] == '\n' || id[k-1] == '\r' || id[k-1] == ' ' ||
                         id[k-1] == '\t' || id[k-1] == 0x1a)) id[--k] = 0;
        coff = djvu_doc_component_offset(doc, id);
        if (!coff) continue;
        {
            const uint8_t *c2 = djvu_form_find_chunk(doc, coff, "ANTz", &sz, NULL);
            if (c2) return (char *)djvu_bzz_decode_all(ctx, c2, sz, out_len);
            c2 = djvu_form_find_chunk(doc, coff, "ANTa", &sz, NULL);
            if (c2) {
                char *buf = (char *)djvu_alloc(ctx, sz + 1);
                if (!buf) return NULL;
                memcpy(buf, c2, sz); buf[sz] = 0;
                *out_len = sz;
                return buf;
            }
        }
    }
    return NULL;
}

djvu_page_links *djvu_page_get_links(djvu_doc *doc, int page_no)
{
    djvu_ctx *ctx;
    char *buf;
    size_t blen = 0;
    sparse sp;
    lcollect lc;
    djvu_page_info info;
    djvu_page_links *res;

    if (!doc || page_no < 0 || page_no >= doc->npages) return NULL;
    ctx = doc->ctx;
    buf = load_anno(doc, doc->pages[page_no].form_off, &blen);
    if (!buf) return NULL;

    memset(&lc, 0, sizeof(lc));
    lc.ctx = ctx; lc.doc = doc;
    lc.page_h = (djvu_doc_page_info(doc, page_no, &info) == 0) ? info.height : 0;

    memset(&sp, 0, sizeof(sp));
    sp.ctx = ctx; sp.s = buf; sp.len = blen;
    /* the annotation body is a sequence of top-level forms */
    while (sp.pos < sp.len) {
        snode *node;
        skip_ws(&sp);
        if (sp.pos >= sp.len || sp.s[sp.pos] != '(') { sp.pos++; continue; }
        node = parse_node(&sp);
        if (!node) break;
        walk(&lc, node);
        snode_free(ctx, node);
    }
    djvu_free(ctx, buf);

    if (lc.n == 0) { djvu_free(ctx, lc.links); return NULL; }

    res = (djvu_page_links *)djvu_alloc(ctx, sizeof(*res));
    if (!res) {
        int i;
        for (i = 0; i < lc.n; i++) { djvu_free(ctx, lc.links[i].url);
                                     djvu_free(ctx, lc.links[i].comment); }
        djvu_free(ctx, lc.links);
        return NULL;
    }
    res->links = lc.links;
    res->nlinks = lc.n;
    return res;
}

void djvu_page_links_destroy(djvu_ctx *ctx, djvu_page_links *links)
{
    int i;
    if (!links) return;
    for (i = 0; i < links->nlinks; i++) {
        djvu_free(ctx, links->links[i].url);
        djvu_free(ctx, links->links[i].comment);
    }
    djvu_free(ctx, links->links);
    djvu_free(ctx, links);
}
